 53→/// Read a JSONL session file and return the fully processed chunk list.
 54→pub fn read_session(path: &str) -> Result<Vec<Chunk>, String> {
 55→    let (msgs, _, _) = read_session_incremental(path, 0)?;
 56→    Ok(build_chunks(&msgs))
 57→}
 58→
 59→/// Read new lines from a session file starting at the given byte offset.
 60→/// Returns (new classified messages, updated offset, bytes read).
 61→pub fn read_session_incremental(
 62→    path: &str,
 63→    offset: u64,
 64→) -> Result<(Vec<ClassifiedMsg>, u64, u64), String> {
 65→    let f = fs::File::open(path).map_err(|e| format!("opening {path}: {e}"))?;
 66→    let mut reader = BufReader::new(f);
 67→    reader
 68→        .seek(SeekFrom::Start(offset))
 69→        .map_err(|e| format!("seeking: {e}"))?;
 70→
 71→    let mut msgs = Vec::new();
 72→    let mut bytes_read: u64 = 0;
 73→    let mut line = String::new();
 74→
 75→    loop {
 76→        line.clear();
 77→        let n = reader
 78→            .read_line(&mut line)
 79→            .map_err(|e| format!("reading: {e}"))?;
 80→        if n == 0 {
 81→            break;
 82→        }
 83→        bytes_read += n as u64;
 84→
 85→        let trimmed = line.trim();
 86→        if trimmed.is_empty() {
 87→            continue;
 88→        }
 89→
 90→        if let Some(entry) = parse_entry(trimmed.as_bytes()) {
 91→            if let Some(msg) = classify(entry) {
 92→                msgs.push(msg);
 93→            }
 94→        }
 95→    }
 96→
 97→    Ok((msgs, offset + bytes_read, bytes_read))
 98→}
