100→/// Return the Claude projects base directory.
101→/// Priority: configured path > CLAUDE_PROJECTS_DIR env var > ~/.claude/projects.
102→pub fn claude_projects_dir(configured: Option<&str>) -> Result<PathBuf, String> {
103→    if let Some(dir) = configured {
104→        let p = PathBuf::from(dir);
105→        if p.exists() {
106→            return Ok(p);
107→        }
108→    }
109→    if let Ok(custom) = std::env::var("CLAUDE_PROJECTS_DIR") {
110→        let p = PathBuf::from(&custom);
111→        if p.exists() {
112→            return Ok(p);
113→        }
114→    }
115→    let home = dirs::home_dir().ok_or("no home directory")?;
116→    Ok(home.join(".claude").join("projects"))
117→}
118→
119→/// Return the Claude CLI projects directory for an absolute path.
120→pub fn project_dir_for_path(abs_path: &str) -> Result<String, String> {
121→    let base = claude_projects_dir(None)?;
122→    let resolved = fs::canonicalize(abs_path).unwrap_or_else(|_| PathBuf::from(abs_path));
123→    let encoded = encode_path(&resolved.to_string_lossy());
124→    Ok(base.join(encoded).to_string_lossy().to_string())
125→}
126→
127→fn encode_path(abs_path: &str) -> String {
128→    abs_path.replace([std::path::MAIN_SEPARATOR, '/', '.', '_'], "-")
129→}
