228→/// Convert scanned metadata into a SessionInfo struct.
229→/// Public for use by SessionCache.
230→pub fn session_info_from_metadata(
231→    path: &str,
232→    mod_time: std::time::SystemTime,
233→    meta: SessionMetadata,
234→) -> SessionInfo {
235→    let mod_time_chrono: DateTime<Utc> = mod_time.into();
236→    let mut is_ongoing = super::ongoing::apply_staleness(meta.is_ongoing, mod_time);
237→    if !is_ongoing {
238→        is_ongoing = super::subagent::has_recently_active_subagents(path);
239→    }
240→    let name = std::path::Path::new(path)
241→        .file_name()
242→        .and_then(|n| n.to_str())
243→        .unwrap_or("");
244→    let session_id = name.trim_end_matches(".jsonl").to_string();
245→
246→    SessionInfo {
247→        path: path.to_string(),
248→        session_id,
249→        mod_time: mod_time_chrono,
250→        first_message: meta.first_msg,
251→        turn_count: meta.turn_count,
252→        is_ongoing,
253→        total_tokens: meta.total_tokens,
254→        input_tokens: meta.input_tokens,
255→        output_tokens: meta.output_tokens,
256→        cache_read_tokens: meta.cache_read_tokens,
257→        cache_creation_tokens: meta.cache_creation_tokens,
258→        cost_usd: meta.cost_usd,
259→        duration_ms: meta.duration_ms,
260→        model: meta.model,
261→        cwd: meta.cwd,
262→        git_branch: meta.git_branch,
263→        permission_mode: meta.permission_mode,
