  50→// ---------------------------------------------------------------------------
  51→// ActivityType — classifies each item in a chunk for ongoing analysis
  52→// ---------------------------------------------------------------------------
  53→
  54→#[derive(Debug, Clone, PartialEq)]
  55→enum ActivityType {
  56→    TextOutput,
  57→    Thinking,
  58→    ToolUse,
  59→    ToolResult,
  60→    Interruption,
  61→    ExitPlanMode,
  62→}
  63→
  64→impl ActivityType {
  65→    fn is_ending(&self) -> bool {
  66→        matches!(
  67→            self,
  68→            ActivityType::TextOutput | ActivityType::Interruption | ActivityType::ExitPlanMode
  69→        )
  70→    }
  71→
  72→    fn is_ai_activity(&self) -> bool {
  73→        matches!(
  74→            self,
  75→            ActivityType::Thinking | ActivityType::ToolUse | ActivityType::ToolResult
  76→        )
  77→    }
  78→}
  79→
  80→// ---------------------------------------------------------------------------
  81→// ActivityLog — collects indexed activities from chunks and checks ongoing
  82→// ---------------------------------------------------------------------------
  83→
  84→struct ActivityLog {
  85→    entries: Vec<(ActivityType, usize)>,
  86→    has_items: bool,
  87→}
  88→
  89→impl ActivityLog {
  90→    /// Scan all AI chunks and build an ordered activity log.
  91→    fn from_chunks(chunks: &[Chunk]) -> Self {
  92→        let mut entries: Vec<(ActivityType, usize)> = Vec::new();
  93→        let mut idx = 0;
  94→        let mut has_items = false;
  95→        let mut shutdown_tool_ids: HashSet<String> = HashSet::new();
  96→
  97→        for chunk in chunks {
  98→            if chunk.chunk_type != ChunkType::AI || chunk.items.is_empty() {
  99→                continue;
 100→            }
 101→            has_items = true;
 102→
 103→            for item in &chunk.items {
 104→                match item.item_type {
 105→                    DisplayItemType::Thinking => {
 106→                        entries.push((ActivityType::Thinking, idx));
 107→                        idx += 1;
 108→                    }
 109→                    DisplayItemType::Output => {
 110→                        if !item.text.trim().is_empty() {
 111→                            entries.push((ActivityType::TextOutput, idx));
 112→                            idx += 1;
 113→                        }
 114→                    }
 115→                    DisplayItemType::ToolCall => {
 116→                        if item.tool_name == "ExitPlanMode" {
 117→                            entries.push((ActivityType::ExitPlanMode, idx));
 118→                            idx += 1;
 119→                        } else if is_shutdown_approval(&item.tool_name, &item.tool_input) {
 120→                            shutdown_tool_ids.insert(item.tool_id.clone());
 121→                            entries.push((ActivityType::Interruption, idx));
 122→                            idx += 1;
 123→                        } else {
 124→                            entries.push((ActivityType::ToolUse, idx));
 125→                            idx += 1;
 126→                        }
 127→                        if !item.tool_result.is_empty() {
 128→                            if shutdown_tool_ids.contains(&item.tool_id) {
 129→                                entries.push((ActivityType::Interruption, idx));
 130→                            } else {
 131→                                entries.push((ActivityType::ToolResult, idx));
 132→                            }
 133→                            idx += 1;
 134→                        }
 135→                    }
 136→                    DisplayItemType::Subagent => {
 137→                        entries.push((ActivityType::ToolUse, idx));
 138→                        idx += 1;
 139→                        if !item.tool_result.is_empty() {
 140→                            entries.push((ActivityType::ToolResult, idx));
 141→                            idx += 1;
 142→                        }
 143→                    }
 144→                    DisplayItemType::TeammateMessage | DisplayItemType::HookEvent => {}
 145→                }
 146→            }
 147→        }
 148→
 149→        Self { entries, has_items }
 150→    }
 151→
 152→    /// True if the last meaningful activity is not an ending (text/interruption).
 153→    fn is_ongoing(&self) -> bool {
 154→        if self.entries.is_empty() {
 155→            return false;
 156→        }
 157→
 158→        let last_ending_idx = self
 159→            .entries
 160→            .iter()
 161→            .rev()
 162→            .find(|(at, _)| at.is_ending())
 163→            .map(|(_, idx)| *idx);
 164→
 165→        match last_ending_idx {
 166→            None => self.entries.iter().any(|(at, _)| at.is_ai_activity()),
 167→            Some(lei) => self
 168→                .entries
 169→                .iter()
 170→                .any(|(at, idx)| *idx > lei && at.is_ai_activity()),
 171→        }
 172→    }
 173→}
