194→/// Discover all subagent and team processes for a session, link them, and return
195→/// the process list with its color map.
196→pub fn discover_and_link_all(
197→    session_path: &str,
198→    chunks: &[Chunk],
199→) -> (Vec<SubagentProcess>, HashMap<String, String>) {
200→    let subagents = discover_subagents(session_path).unwrap_or_default();
201→    let team_procs = discover_team_sessions(session_path, chunks).unwrap_or_default();
202→    let mut all_procs: Vec<SubagentProcess> = subagents;
203→    all_procs.extend(team_procs);
204→    let color_map = link_subagents(&mut all_procs, chunks, session_path);
205→    (all_procs, color_map)
206→}
