208→/// Discover and parse subagent files for a session.
209→pub fn discover_subagents(session_path: &str) -> Result<Vec<SubagentProcess>, String> {
210→    let dir = Path::new(session_path).parent().unwrap_or(Path::new(""));
211→    let base = Path::new(session_path)
212→        .file_stem()
213→        .and_then(|s| s.to_str())
214→        .unwrap_or("");
215→    let subagents_dir = dir.join(base).join("subagents");
216→
217→    let entries = match fs::read_dir(&subagents_dir) {
218→        Ok(e) => e,
219→        Err(_) => return Ok(Vec::new()),
220→    };
221→
222→    let mut procs = Vec::new();
223→
224→    for entry in entries.flatten() {
225→        let name = entry.file_name().to_string_lossy().to_string();
226→        if !name.starts_with("agent-") || !name.ends_with(".jsonl") {
227→            continue;
228→        }
229→
230→        let agent_id = name
231→            .strip_prefix("agent-")
232→            .unwrap_or("")
233→            .strip_suffix(".jsonl")
234→            .unwrap_or("")
235→            .to_string();
236→
237→        let file_path = subagents_dir.join(&name).to_string_lossy().to_string();
238→
239→        let metadata = entry.metadata().map_err(|e| e.to_string())?;
240→        if metadata.len() == 0 {
241→            continue;
242→        }
243→
244→        if is_warmup_agent(&file_path) {
245→            continue;
246→        }
