 30→/// Reconstruct team task boards from chunks and worker processes.
 31→pub fn reconstruct_teams(chunks: &[Chunk], workers: &[SubagentProcess]) -> Vec<TeamSnapshot> {
 32→    let mut teams: Vec<TeamSnapshot> = Vec::new();
 33→    let mut active_idx: Option<usize> = None;
 34→    let mut task_counter = 0;
 35→
 36→    // Phase 1: Lead chunk events.
 37→    for c in chunks {
 38→        if c.chunk_type != ChunkType::AI {
 39→            continue;
 40→        }
 41→        for item in &c.items {
 42→            match (&item.item_type, item.tool_name.as_str()) {
 43→                (DisplayItemType::ToolCall, "TeamCreate") => {
 44→                    teams.push(team_snapshot_from_create(&item.tool_input));
 45→                    active_idx = Some(teams.len() - 1);
 46→                    task_counter = 0;
 47→                }
 48→                (DisplayItemType::ToolCall, "TaskCreate") if active_idx.is_some() => {
 49→                    task_counter += 1;
 50→                    let task = team_task_from_create(&item.tool_input, task_counter);
 51→                    teams[active_idx.unwrap()].tasks.push(task);
 52→                }
 53→                (DisplayItemType::ToolCall, "TaskUpdate") if active_idx.is_some() => {
 54→                    apply_team_task_update(&item.tool_input, &mut teams[active_idx.unwrap()]);
 55→                }
 56→                (DisplayItemType::ToolCall, "TeamDelete") if active_idx.is_some() => {
 57→                    teams[active_idx.unwrap()].deleted = true;
 58→                    active_idx = None;
 59→                }
 60→                (DisplayItemType::Subagent, _) if is_team_task(item) => {
 61→                    add_team_spawn_member(&item.tool_input, &mut teams);
 62→                }
 63→                _ => {}
 64→            }
 65→        }
 66→    }
 67→
 68→    // Phase 2: Worker TaskUpdate events.
 69→    for worker in workers {
 70→        let (agent_name, team_name) = split_worker_id(&worker.id);
 71→        if team_name.is_empty() {
 72→            continue;
 73→        }
 74→        if let Some(team) = find_team_by_name_mut(&mut teams, &team_name) {
 75→            apply_worker_task_updates(&worker.chunks, team, &agent_name);
 76→        }
 77→    }
 78→
 79→    // Phase 3: Populate member colors.
 80→    for team in &mut teams {
 81→        team.member_colors = HashMap::new();
 82→        team.member_ongoing = HashMap::new();
 83→    }
 84→    for worker in workers {
 85→        let (agent_name, team_name) = split_worker_id(&worker.id);
 86→        if team_name.is_empty() || worker.teammate_color.is_empty() {
 87→            continue;
 88→        }
 89→        for team in &mut teams {
 90→            if team.name == team_name {
 91→                team.member_colors
 92→                    .insert(agent_name.clone(), worker.teammate_color.clone());
 93→            }
 94→        }
 95→    }
 96→
 97→    // Phase 4: Populate member ongoing state.
 98→    for worker in workers {
 99→        let (agent_name, team_name) = split_worker_id(&worker.id);
100→        if team_name.is_empty() {
101→            continue;
102→        }
103→        if OngoingChecker::is_chunks_ongoing(&worker.chunks) {
104→            for team in &mut teams {
105→                if team.name == team_name {
106→                    team.member_ongoing.insert(agent_name.clone(), true);
107→                }
108→            }
109→        }
110→    }
111→
112→    teams
113→}
