179→fn apply_worker_task_updates(chunks: &[Chunk], team: &mut TeamSnapshot, worker_name: &str) {
180→    for c in chunks {
181→        if c.chunk_type != ChunkType::AI {
182→            continue;
183→        }
184→        for item in &c.items {
185→            if item.item_type != DisplayItemType::ToolCall || item.tool_name != "TaskUpdate" {
186→                continue;
187→            }
188→            let task_id = get_single_field(&item.tool_input, "taskId");
189→            if task_id.is_empty() {
190→                continue;
191→            }
192→            for task in &mut team.tasks {
193→                if task.id != task_id {
194→                    continue;
195→                }
196→                let status = get_single_field(&item.tool_input, "status");
197→                if !status.is_empty() {
198→                    task.status = status;
199→                }
200→                let owner = get_single_field(&item.tool_input, "owner");
201→                if !owner.is_empty() {
202→                    task.owner = owner;
203→                } else if task.owner.is_empty() {
204→                    task.owner = worker_name.to_string();
205→                }
206→                let subject = get_single_field(&item.tool_input, "subject");
207→                if !subject.is_empty() {
208→                    task.subject = subject;
209→                }
210→            }
211→        }
212→    }
213→}
