  4→/// Returns a display name for a project directory.
  5→pub fn project_name(cwd: &str, git_branch: &str) -> String {
  6→    if cwd.is_empty() {
  7→        return String::new();
  8→    }
  9→    let cleaned = Path::new(cwd).to_path_buf();
 10→
 11→    if let Some(root) = find_git_repo_root(&cleaned) {
 12→        return root
 13→            .file_name()
 14→            .and_then(|n| n.to_str())
 15→            .unwrap_or("")
 16→            .to_string();
 17→    }
 18→
 19→    let name = cleaned
 20→        .file_name()
 21→        .and_then(|n| n.to_str())
 22→        .unwrap_or("")
 23→        .to_string();
 24→    trim_branch_suffix(&name, git_branch)
 25→}
 26→
 27→/// Returns the git toplevel for the given directory. If the directory is
 28→/// inside a git worktree, resolves to the main working tree root.
 29→/// Falls back to the original path if not a git repo.
 30→pub fn resolve_git_root(dir: &str) -> String {
 31→    if let Some(root) = find_git_repo_root(Path::new(dir)) {
 32→        root.to_string_lossy().to_string()
 33→    } else {
 34→        dir.to_string()
 35→    }
 36→}
 37→
 38→fn find_git_repo_root(dir: &Path) -> Option<PathBuf> {
 39→    let mut current = if dir.is_dir() {
 40→        dir.to_path_buf()
 41→    } else {
 42→        dir.parent()?.to_path_buf()
 43→    };
 44→
 45→    loop {
 46→        let git_path = current.join(".git");
 47→        if let Ok(meta) = fs::metadata(&git_path) {
 48→            if meta.is_dir() {
 49→                return Some(current);
 50→            }
 51→            if meta.is_file() {
 52→                // Worktree: try to resolve main repo root
 53→                if let Some(root) = repo_root_from_git_file(&current, &git_path) {
 54→                    return Some(root);
 55→                }
 56→                return Some(current);
 57→            }
 58→        }
 59→        if !current.pop() {
 60→            return None;
 61→        }
 62→    }
 63→}
 64→
 65→fn repo_root_from_git_file(repo_dir: &Path, git_file: &Path) -> Option<PathBuf> {
 66→    let content = fs::read_to_string(git_file).ok()?;
 67→    let git_dir_str = content
 68→        .lines()
 69→        .find(|l| l.to_lowercase().starts_with("gitdir:"))?
 70→        .trim_start_matches(|c: char| !c.is_ascii_whitespace() && c != ':')
 71→        .trim_start_matches(':')
 72→        .trim();
 73→
 74→    let git_dir = if Path::new(git_dir_str).is_absolute() {
 75→        PathBuf::from(git_dir_str)
 76→    } else {
 77→        git_file.parent()?.join(git_dir_str).canonicalize().ok()?
 78→    };
 79→
 80→    // Try commondir
 81→    let common_dir_path = git_dir.join("commondir");
 82→    if let Ok(common_content) = fs::read_to_string(&common_dir_path) {
 83→        let common = common_content.trim();
 84→        let common_path = if Path::new(common).is_absolute() {
 85→            PathBuf::from(common)
 86→        } else {
 87→            git_dir.join(common).canonicalize().ok()?
 88→        };
 89→        if common_path.file_name().and_then(|n| n.to_str()) == Some(".git") {
 90→            return common_path.parent().map(|p| p.to_path_buf());
 91→        }
 92→    }
 93→
 94→    // Fallback: parse worktrees path
 95→    let git_dir_str = git_dir.to_string_lossy();
 96→    let marker = format!(
 97→        "{}worktrees{}",
 98→        std::path::MAIN_SEPARATOR,
 99→        std::path::MAIN_SEPARATOR
100→    );
101→    if let Some(idx) = git_dir_str.find(&format!(".git{marker}")) {
102→        let root = &git_dir_str[..idx];
103→        if !root.is_empty() {
104→            return Some(PathBuf::from(
105→                root.trim_end_matches(std::path::MAIN_SEPARATOR),
106→            ));
107→        }
108→    }
109→
110→    Some(repo_dir.to_path_buf())
111→}
112→
113→fn trim_branch_suffix(name: &str, git_branch: &str) -> String {
114→    let branch = git_branch.trim().trim_start_matches("refs/heads/");
115→    if name.is_empty() || branch.is_empty() {
116→        return name.to_string();
117→    }
118→    let branch_token = normalize_branch_token(branch);
119→    if branch_token.is_empty() || is_default_branch(&branch_token) {
120→        return name.to_string();
121→    }
122→
123→    for sep in &["-", "_"] {
124→        let suffix = format!("{sep}{branch_token}");
125→        if name.to_lowercase().ends_with(&suffix.to_lowercase()) {
126→            let base = name[..name.len() - suffix.len()].trim_end_matches(&['-', '_'][..]);
127→            if !base.is_empty() {
128→                return base.to_string();
129→            }
130→        }
131→    }
132→    name.to_string()
133→}
134→
135→fn normalize_branch_token(branch: &str) -> String {
136→    let mut result = String::with_capacity(branch.len());
137→    let mut last_dash = false;
138→    for c in branch.chars() {
139→        if c.is_alphanumeric() {
140→            result.push(c.to_lowercase().next().unwrap_or(c));
141→            last_dash = false;
142→        } else if !last_dash {
143→            result.push('-');
144→            last_dash = true;
145→        }
146→    }
147→    result.trim_matches('-').to_string()
148→}
149→
150→fn is_default_branch(branch: &str) -> bool {
151→    matches!(
152→        branch.to_lowercase().as_str(),
153→        "main" | "master" | "trunk" | "develop" | "dev"
154→    )
155→}
