127→/// Parse an ISO 8601 timestamp. Returns epoch on failure.
128→pub fn parse_timestamp(s: &str) -> DateTime<Utc> {
129→    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
130→        return dt.with_timezone(&Utc);
131→    }
132→    // Try without timezone
133→    if let Ok(naive) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f") {
134→        return Utc.from_utc_datetime(&naive);
135→    }
136→    Utc::now() // fallback; ideally epoch but using now for simplicity
137→}
