139→/// Classify maps a raw Entry to a ClassifiedMsg. Returns None for noise.
140→pub fn classify(e: Entry) -> Option<ClassifiedMsg> {
141→    if e.is_sidechain {
142→        return None;
143→    }
144→
145→    let ts = parse_timestamp(&e.timestamp);
146→
147→    // Rescue hook_progress from noise filter before discarding all "progress" entries.
148→    if e.entry_type == "progress" {
149→        if let Some(ref data) = e.data {
150→            if data.get("type").and_then(|v| v.as_str()) == Some("hook_progress") {
151→                let hook_event = data
152→                    .get("hookEvent")
153→                    .and_then(|v| v.as_str())
154→                    .unwrap_or("")
155→                    .to_string();
156→                let hook_name = data
157→                    .get("hookName")
158→                    .and_then(|v| v.as_str())
159→                    .unwrap_or("")
160→                    .to_string();
161→                let command = data
162→                    .get("command")
163→                    .and_then(|v| v.as_str())
164→                    .unwrap_or("")
165→                    .to_string();
166→                return Some(ClassifiedMsg::Hook(HookMsg {
167→                    timestamp: ts,
168→                    hook_event,
169→                    hook_name,
170→                    command,
171→                }));
172→            }
173→        }
174→    }
175→
176→    // Hard noise: structural metadata types.
177→    if NOISE_ENTRY_TYPES.contains(&e.entry_type.as_str()) {
178→        return None;
179→    }
180→
181→    // Summary entries -> CompactMsg.
182→    if e.entry_type == "summary" {
183→        return Some(ClassifiedMsg::Compact(CompactMsg {
184→            timestamp: ts,
185→            text: e.summary.clone(),
186→        }));
187→    }
188→
189→    // Synthetic assistant messages.
190→    if e.entry_type == "assistant" && e.message.model == "<synthetic>" {
191→        return None;
192→    }
193→
194→    let content_str = extract_text(&e.message.content);
195→
196→    // Filter user-type noise.
197→    if e.entry_type == "user" && is_user_noise(&e.message.content, &content_str) {
198→        return None;
199→    }
